/**
 * @summary List all charities
 */
export const getListCharitiesUrl = (params?: ListCharitiesParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/charities?${stringifiedParams}`
    : `/api/charities`;
};

export const listCharities = async (
  params?: ListCharitiesParams,
  options?: RequestInit,
): Promise<Charity[]> => {
  return customFetch<Charity[]>(getListCharitiesUrl(params), {
    ...options,
    method: "GET",
  });
};

